## Implementation Plan: Stepper Compound Component

### Architecture Overview

The Stepper uses two nested React contexts:
1. `StepperContext` — shared by all children, carries `activeStep` and `orientation`
2. `StepperItemContext` — scoped to each `StepperItem`, carries the item's `step` number and derived `state`

This mirrors the `ToggleGroup`/`ToggleGroupItem` and `Carousel`/`CarouselItem` patterns already present in the codebase.

---

### File 1: `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  step: number
  state: "active" | "completed" | "pending"
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

function Stepper({
  activeStep = 1,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep, orientation } = useStepper()

  const state: "active" | "completed" | "pending" =
    activeStep === step
      ? "active"
      : activeStep > step
        ? "completed"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "flex items-center",
          orientation === "horizontal" ? "flex-row" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-full size-8 text-sm font-medium transition-colors outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        state === "pending" &&
          "border-2 border-muted-foreground/30 text-muted-foreground bg-background",
        state === "active" && "bg-primary text-primary-foreground",
        state === "completed" &&
          "bg-primary text-primary-foreground opacity-80",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()
  const { step } = useStepperItem()

  const completed = activeStep > step

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-completed={completed}
      className={cn(
        "shrink-0 bg-border transition-colors",
        orientation === "horizontal"
          ? "h-px flex-1 min-w-4"
          : "w-px flex-1 min-h-4",
        completed && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium",
        state === "pending" ? "text-muted-foreground" : "text-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { activeStep } = useStepper()
  const { step } = useStepperItem()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2 text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperSeparator,
  StepperTitle,
  StepperDescription,
  StepperContent,
}
```

