## Step 1 — Create `apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ── Root context ──────────────────────────────────────────────────────────────

type StepperContextProps = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ── Item context ──────────────────────────────────────────────────────────────

type StepperItemContextProps = {
  step: number
  state: "active" | "completed" | "pending"
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ── Components ────────────────────────────────────────────────────────────────

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep, orientation } = useStepper()

  const state: "active" | "completed" | "pending" =
    activeStep === step ? "active" : activeStep > step ? "completed" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        data-orientation={orientation}
        className={cn("flex items-center", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-full size-8 text-sm font-medium transition-colors outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        state === "pending" &&
          "border-2 border-muted-foreground/30 bg-background text-muted-foreground",
        state === "active" && "bg-primary text-primary-foreground",
        state === "completed" && "bg-primary text-primary-foreground opacity-80",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium",
        state === "pending" ? "text-muted-foreground" : "text-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()
  const { step } = useStepperItem()

  const completed = activeStep > step

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-completed={completed}
      className={cn(
        "shrink-0 bg-border transition-colors",
        orientation === "horizontal" ? "h-px flex-1 min-w-4" : "w-px flex-1 min-h-4",
        completed && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2 text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

**Key design notes:**
- `StepperTrigger` renders `{children ?? step}` — shows step number by default, custom content if provided
- `StepperSeparator.completed = activeStep > step` — separator after step N fills when moving to step N+1
- `StepperContent` returns `null` (not hidden) when inactive — keeps DOM clean
- No external dependencies — pure React + Tailwind

---

## Step 2 — Create `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

The demo uses **two** `<Stepper>` instances sharing the same `activeStep` state:
1. First: horizontal indicator row with `StepperItem`, `StepperTrigger`, `StepperTitle`, `StepperSeparator`
2. Second: flex-col content area with `StepperContent` panels (flex-col via className override)

Plain `<button>` elements for Previous/Next (keeps registry deps as `["stepper"]` only, no button dep needed).

```tsx
"use client"

import * as React from "react"

import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-sm flex-col gap-8">
      <Stepper activeStep={activeStep} className="w-full">
        <StepperItem step={1} className="flex-1 flex-col items-start gap-1.5">
          <div className="flex w-full items-center gap-2">
            <StepperTrigger />
            <StepperSeparator />
          </div>
          <StepperTitle>Account</StepperTitle>
        </StepperItem>
        <StepperItem step={2} className="flex-1 flex-col items-start gap-1.5">
          <div className="flex w-full items-center gap-2">
            <StepperTrigger />
            <StepperSeparator />
          </div>
          <StepperTitle>Profile</StepperTitle>
        </StepperItem>
        <StepperItem step={3} className="flex-col items-start gap-1.5">
          <StepperTrigger />
          <StepperTitle>Complete</StepperTitle>
        </StepperItem>
      </Stepper>

      <Stepper activeStep={activeStep} className="flex-col">
        <StepperContent step={1}>
          <p className="text-muted-foreground">
            Set up your account credentials and basic information.
          </p>
        </StepperContent>
        <StepperContent step={2}>
          <p className="text-muted-foreground">
            Complete your profile with a bio and avatar.
          </p>
        </StepperContent>
        <StepperContent step={3}>
          <p className="text-muted-foreground">
            All done! Your account setup is complete.
          </p>
        </StepperContent>
      </Stepper>

      <div className="flex gap-2">
        <button
          type="button"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
          className="inline-flex h-9 items-center rounded-md border px-4 text-sm font-medium transition-colors hover:bg-accent disabled:pointer-events-none disabled:opacity-50"
        >
          Previous
        </button>
        <button
          type="button"
          onClick={() => setActiveStep((s) => Math.min(3, s + 1))}
          disabled={activeStep === 3}
          className="inline-flex h-9 items-center rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:pointer-events-none disabled:opacity-50"
        >
          Next
        </button>
      </div>
    </div>
  )
}
```

**Layout note:** The second `<Stepper className="flex-col">` overrides the default `flex-row` via Tailwind Merge (both `flex-row` and `flex-col` begin with `flex-`, so the latter wins). This makes the content Stepper stack panels vertically while only one renders at a time.

---

## Step 3 — Edit `apps/v4/registry/new-york-v4/ui/_registry.ts`

Insert between the `spinner` entry (currently ending ~line 563) and the `switch` entry (currently starting ~line 565). No `dependencies` key needed (pure React).

```ts
  {
    name: "stepper",
    type: "registry:ui",
    files: [
      {
        path: "ui/stepper.tsx",
        type: "registry:ui",
      },
    ],
  },
```

**Edit target** — use this as the `old_string`:
```
  {
    name: "switch",
    type: "registry:ui",
```
Replace with the new stepper entry prepended before it.

---

## Step 4 — Edit `apps/v4/registry/new-york-v4/examples/_registry.ts`

Insert after the last spinner-related entry (`spinner-badge`, ending ~line 2120) and before the `switch-demo` entry (~line 2126).

```ts
  {
    name: "stepper-demo",
    type: "registry:example",
    registryDependencies: ["stepper"],
    files: [
      {
        path: "examples/stepper-demo.tsx",
        type: "registry:example",
      },
    ],
  },
```

---

## Verification

1. **TypeScript check**: Run `pnpm tsc --noEmit` from `apps/v4/` — should produce no errors for the new files
2. **Registry validation**: Run `pnpm build:registry` (or equivalent) — new entries should be picked up
3. **Visual check**: Open the demo in the Next.js dev server; clicking Next/Previous should:
   - Update trigger colors (pending → active → completed)
   - Fill separators progressively
   - Swap content panels
4. **Data attributes**: Inspect DOM — verify `data-slot`, `data-state`, `data-orientation`, `data-step`, `data-completed` appear on all elements

