  return (
    <div
      data-slot="stepper-separator"
      data-filled={filled}
      className={cn(
        "shrink-0 rounded-full bg-muted transition-colors",
        orientation === "horizontal" ? "h-0.5 flex-1" : "w-0.5 flex-1 min-h-6",
        filled && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent — content panel shown only for the active step
// ---------------------------------------------------------------------------

type StepperContentProps = React.ComponentProps<"div"> & {
