"use client"

import * as React from "react"

import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content: "Enter your email address and choose a secure password to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content: "Tell us a bit about yourself so we can personalise your experience.",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set!",
    content: "Your account is ready. Welcome aboard — enjoy the experience.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-xl flex-col gap-6 p-4">
      {/* Step indicator row */}
      <Stepper activeStep={activeStep} orientation="horizontal">
        {steps.map(({ step, title, description }) => (
          <React.Fragment key={step}>
            <StepperItem step={step} className="flex-col items-center gap-2">
              <StepperTrigger onClick={() => setActiveStep(step)} />
              <div className="flex flex-col items-center gap-0.5 text-center">
                <StepperTitle>{title}</StepperTitle>
                <StepperDescription>{description}</StepperDescription>
              </div>
            </StepperItem>
            {step < steps.length && (
              <StepperSeparator className="mx-2 mb-6" />
            )}
          </React.Fragment>
        ))}
      </Stepper>

      {/* Content panels */}
      <Stepper activeStep={activeStep} orientation="horizontal" className="flex-col">
        {steps.map(({ step, title, content }) => (
          <StepperContent key={step} step={step} className="mt-0 w-full">
            <div className="rounded-lg border bg-card p-6 text-card-foreground shadow-sm">
              <h3 className="mb-2 text-lg font-semibold">{title}</h3>
              <p className="text-sm text-muted-foreground">{content}</p>
            </div>
          </StepperContent>
        ))}
      </Stepper>

      {/* Navigation */}
      <div className="flex justify-between">
        <button
          type="button"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
          className="inline-flex h-9 items-center justify-center rounded-md border border-input bg-background px-4 text-sm font-medium shadow-sm transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50"
        >
          Previous
        </button>
        <button
          type="button"
          onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
          disabled={activeStep === steps.length}
          className="inline-flex h-9 items-center justify-center rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground shadow transition-colors hover:bg-primary/90 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50"
        >
          Next
        </button>
      </div>
    </div>
  )
}

