"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("Stepper components must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextValue = {
  step: number
  state: "active" | "completed" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItemContext() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error(
      "StepperTrigger must be used within a <StepperItem />"
    )
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper — root container
// ---------------------------------------------------------------------------

type StepperProps = React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem — per-step wrapper
// ---------------------------------------------------------------------------

type StepperItemProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = useStepperContext()

  const state: "active" | "completed" | "pending" =
    step === activeStep
      ? "active"
      : step < activeStep
        ? "completed"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "flex items-center",
          orientation === "horizontal" ? "flex-row" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger — circle button showing step number
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItemContext()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        state === "active" &&
          "border-primary bg-primary text-primary-foreground",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "pending" &&
          "border-muted-foreground/30 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle — label text for a step
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItemContext()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none transition-colors",
        state === "active" && "text-foreground",
        state === "completed" && "text-foreground",
        state === "pending" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription — description text for a step
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItemContext()

  return (
    <p
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs transition-colors",
        state === "active" && "text-muted-foreground",
        state === "completed" && "text-muted-foreground",
        state === "pending" && "text-muted-foreground/50",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator — line between steps
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepperContext()
  const { step } = useStepperItemContext()

  // The separator fills when the NEXT step is completed, i.e. activeStep > step + 1
  const filled = activeStep > step

  return (
    <div
      data-slot="stepper-separator"
      data-filled={filled}
      className={cn(
        "shrink-0 rounded-full bg-muted transition-colors",
        orientation === "horizontal" ? "h-0.5 flex-1" : "w-0.5 flex-1 min-h-6",
        filled && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent — content panel shown only for the active step
// ---------------------------------------------------------------------------

type StepperContentProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { activeStep } = useStepperContext()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      data-step={step}
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
